"use client"

import { useState, useEffect, useMemo, useRef } from "react";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogTitle } from "@/components/ui/dialog";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
} from "@/components/ui/carousel";
import {
  Loader2, Timer, Trophy, RotateCcw, Gauge, Zap, Square, MapPin, Star, ChevronRight, X, Activity, Clock, Signal, SignalHigh, SignalLow, Play, AlertCircle, ShieldAlert, Radio, Navigation, CircleSlash, RefreshCcw, TrendingUp, ArrowDown
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking, useCollection } from "@/firebase";
import { doc, collection, query, limit, where, orderBy } from "firebase/firestore";
import { useDriving, RunMode } from "@/context/driving-context";
import dynamic from "next/dynamic";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-zinc-900 animate-pulse rounded-[1.8rem] flex items-center justify-center text-[8px] font-bold text-white/20 uppercase tracking-widest">Duke hapur hartën...</div>
});

function describeArc(x: number, y: number, radius: number, startAngle: number, endAngle: number) {
  const polarToCartesian = (cX: number, cY: number, rad: number, angleDeg: number) => {
    const rads = ((angleDeg - 90) * Math.PI) / 180.0;
    return { x: cX + rad * Math.cos(rads), y: cY + rad * Math.sin(rads) };
  };
  const start = polarToCartesian(x, y, radius, endAngle);
  const end = polarToCartesian(x, y, radius, startAngle);
  const largeArcFlag = endAngle - startAngle <= 180 ? "0" : "1";
  return ["M", start.x, start.y, "A", radius, radius, 0, largeArcFlag, 0, end.x, end.y].join(" ");
}

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const {
    speed, isDriving, peakSpeed, tripTime, tripDistance, gpsAccuracy, hasGps,
    startTrip, startDragCountdown, stopTrip, resetTrip,
    runMode, setRunMode, dragTime, isDragFinished, isDragActive,
    lastRunSummary, setLastRunSummary, countdown, isJumpStart, currentCoords
  } = useDriving();

  const [mounted, setMounted] = useState(false);
  const [activeModule, setActiveModule] = useState<'top-speed' | 'drag'>('top-speed');
  const [isSaving, setIsSaving] = useState(false);
  
  // Real-time smooth interpolation system
  const [displaySpeed, setDisplaySpeed] = useState(0);
  const targetSpeedRef = useRef(0);
  const requestRef = useRef<number | null>(null);

  useEffect(() => {
    targetSpeedRef.current = speed;
  }, [speed]);

  useEffect(() => {
    const animate = () => {
      setDisplaySpeed(prev => {
        const target = targetSpeedRef.current;
        const diff = target - prev;
        
        // Snap to target if very close to avoid micro-jitter
        if (Math.abs(diff) < 0.05) return target;
        
        // Easing factor: 0.15 provides a balance between responsive and fluid
        return prev + diff * 0.15;
      });
      requestRef.current = requestAnimationFrame(animate);
    };

    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  const profileRef = useMemoFirebase(() => (!user?.uid || isUserLoading || !db ? null : doc(db, "users", user.uid)), [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  const publicRunsQuery = useMemoFirebase(() => (!db || !user ? null : query(collection(db, "public_runs"), limit(1000))), [db, user]);
  const { data: allPublicRuns } = useCollection(publicRunsQuery);

  const radarReportsQuery = useMemoFirebase(() => {
    if (!db || !user) return null;
    const threeHoursAgo = new Date();
    threeHoursAgo.setHours(threeHoursAgo.getHours() - 3);
    return query(
      collection(db, "radar_reports"),
      where("createdAt", ">=", threeHoursAgo.toISOString()),
      orderBy("createdAt", "desc"),
      limit(50)
    );
  }, [db, user]);

  const { data: radarReports } = useCollection(radarReportsQuery);

  const activeRadarAlert = useMemo(() => {
    if (!currentCoords || !radarReports) return null;
    
    const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
      const R = 6371e3;
      const p1 = lat1 * Math.PI / 180;
      const p2 = lat2 * Math.PI / 180;
      const dp = (lat2 - lat1) * Math.PI / 180;
      const dl = (lon2 - lon1) * Math.PI / 180;
      const a = Math.sin(dp/2) * Math.sin(dp/2) + Math.cos(p1) * Math.cos(p2) * Math.sin(dl/2) * Math.sin(dl/2);
      return R * (2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));
    };

    const nearby = radarReports.map(r => ({
      ...r,
      currentDistance: calculateDistance(currentCoords.lat, currentCoords.lng, r.lat, r.lng)
    })).filter(r => r.currentDistance <= 2000)
       .sort((a, b) => a.currentDistance - b.currentDistance);

    return nearby.length > 0 ? nearby[0] : null;
  }, [currentCoords, radarReports]);

  const getRank = (type: string, value: number, city?: string) => {
    if (!allPublicRuns) return "--";
    const isTimeBased = ['0-60', '0-100', '100-200', '1/4 Mile'].includes(type);
    const cityRuns = city ? allPublicRuns.filter(r => r.city === city) : allPublicRuns;
    const typeRuns = cityRuns.filter(r => r.runType === type);
    const bestPerUser: Record<string, number> = {};
    typeRuns.forEach(r => {
      const val = isTimeBased ? r.dragTime : r.peakSpeedKmH;
      if (val === null || val === undefined) return;
      if (!bestPerUser[r.userId]) bestPerUser[r.userId] = val;
      else bestPerUser[r.userId] = isTimeBased ? Math.min(bestPerUser[r.userId], val) : Math.max(bestPerUser[r.userId], val);
    });
    const betterUsers = Object.values(bestPerUser).filter(val => isTimeBased ? val < value : val > value);
    return betterUsers.length + 1;
  };

  const currentRunRanks = useMemo(() => {
    if (!lastRunSummary || !profile) return { city: "--", kosovo: "--" };
    if (lastRunSummary.runType === 'ALL') return { city: "--", kosovo: "--" }; 
    const val = ['0-60', '0-100', '100-200', '1/4 Mile'].includes(lastRunSummary.runType) ? lastRunSummary.time : lastRunSummary.peakSpeed;
    return { city: getRank(lastRunSummary.runType, val, profile.city), kosovo: getRank(lastRunSummary.runType, val) };
  }, [lastRunSummary, allPublicRuns, profile]);

  useEffect(() => { setMounted(true); }, []);

  const handleModuleChange = (module: 'top-speed' | 'drag') => {
    setActiveModule(module);
    setRunMode(module === 'top-speed' ? 'free' : '0-60');
  };

  const themeColor = activeModule === 'drag' ? "#eab308" : "#ffffff";

  const handleSaveToLeaderboard = async () => {
    if (!db || !user || !lastRunSummary || !profile) return;
    setIsSaving(true);
    try {
      const baseRun = {
        userId: user.uid,
        username: profile.username,
        profileIcon: profile.profileIcon || "speedometer",
        city: profile.city || "Kosovë",
        carBrand: profile.carBrand || "Unknown",
        carModel: profile.carModel || "Unknown",
        telemetry: lastRunSummary.telemetry || [],
        path: (lastRunSummary.points || []).map(p => ({ lat: p[0], lng: p[1] })),
        createdAt: new Date().toISOString(),
        brakes: lastRunSummary.brakes,
        turns: lastRunSummary.turns,
        lowSpeedPasses: lastRunSummary.lowSpeedPasses,
        maxGForce: lastRunSummary.maxGForce
      };

      if (lastRunSummary.runType === 'ALL' && lastRunSummary.allStats) {
        Object.entries(lastRunSummary.allStats).forEach(([type, time]) => {
          addDocumentNonBlocking(collection(db, "public_runs"), {
            ...baseRun,
            runType: type,
            dragTime: time,
            peakSpeedKmH: lastRunSummary.peakSpeed,
            distanceMeters: lastRunSummary.distance,
            durationSeconds: time,
          });
        });
      } else {
        addDocumentNonBlocking(collection(db, "public_runs"), {
          ...baseRun,
          runType: lastRunSummary.runType,
          dragTime: ['0-60', '0-100', '100-200', '1/4 Mile'].includes(lastRunSummary.runType) ? lastRunSummary.time : null,
          peakSpeedKmH: lastRunSummary.peakSpeed,
          distanceMeters: lastRunSummary.distance,
          durationSeconds: lastRunSummary.time,
        });
      }
      
      setLastRunSummary(null);
      router.push(lastRunSummary.runType === 'Top Speed' ? "/leaderboard" : "/drag-ranking");
    } finally { setIsSaving(false); }
  };

  const gpsStatus = useMemo(() => {
    if (!hasGps) return { icon: SignalLow, color: "text-red-500", label: "JO GPS" };
    if (gpsAccuracy === null) return { icon: Signal, color: "text-zinc-500", label: "KËRKIM..." };
    if (gpsAccuracy < 10) return { icon: SignalHigh, color: "text-green-500", label: "PRO" };
    if (gpsAccuracy < 30) return { icon: Signal, color: "text-yellow-500", label: "MIRË" };
    return { icon: SignalLow, color: "text-orange-500", label: "DOBËT" };
  }, [hasGps, gpsAccuracy]);

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  const rpmValue = Math.min((displaySpeed / 240) * 8, 8.5);
  const startAngle = 135; 
  const currentProgressAngle = startAngle + (rpmValue / 8) * (405 - 135);

  const isDragModule = activeModule === 'drag';

  return (
    <div className="flex flex-col h-full w-full text-white pb-32 overflow-x-hidden safe-top relative bg-black no-scrollbar">
      <div className="absolute inset-0 bg-gradient-to-b from-red-950/40 via-black to-black pointer-events-none z-0" />

      <div className="absolute top-12 left-6 z-50 flex items-center gap-2 bg-black/40 backdrop-blur-xl px-3 py-1.5 rounded-full border border-white/5 apple-slide-up">
        <gpsStatus.icon className={cn("w-3 h-3", gpsStatus.color)} />
        <span className="text-[8px] font-bold uppercase tracking-widest">{gpsStatus.label}</span>
        {gpsAccuracy !== null && <span className="text-[8px] font-light text-white/30">{Math.round(gpsAccuracy)}m</span>}
      </div>

      <div className="flex-1 flex flex-col items-center justify-center p-4 relative z-10 w-full max-w-[340px] mx-auto">
        <div className="flex gap-1.5 mb-8 bg-white/5 p-1 rounded-2xl border border-white/5 backdrop-blur-3xl apple-slide-up w-fit">
          <button onClick={() => handleModuleChange('top-speed')} className={cn("px-4 py-2.5 rounded-xl font-bold text-[9px] uppercase tracking-widest transition-all flex items-center gap-1.5", activeModule === 'top-speed' ? "bg-white text-black shadow-lg" : "text-white/40 hover:text-white")}><Gauge className="w-3.5 h-3.5" /> TOP SPEED</button>
          <button onClick={() => handleModuleChange('drag')} className={cn("px-4 py-2.5 rounded-xl font-bold text-[9px] uppercase tracking-widest transition-all flex items-center gap-1.5", activeModule === 'drag' ? "bg-yellow-500 text-black shadow-[0_0_15px_#eab308]" : "text-white/40 hover:text-white")}><Zap className="w-3.5 h-3.5" /> MODI DRAG</button>
        </div>

        {activeRadarAlert && (
          <div className="w-full mb-6 apple-slide-up stagger-1 px-2">
            <div className="glass-card border-red-500/30 bg-red-600/5 p-4 rounded-[2rem] flex items-center gap-4 shadow-2xl relative overflow-hidden group">
              <div className="absolute inset-0 bg-gradient-to-r from-red-600/10 to-transparent opacity-50" />
              <div className="w-12 h-12 bg-red-600 rounded-2xl flex items-center justify-center shadow-[0_0_20px_rgba(220,38,38,0.4)] shrink-0 animate-pulse-glow z-10">
                <ShieldAlert className="w-6 h-6 text-white" />
              </div>
              <div className="flex-1 min-w-0 z-10">
                <p className="text-[9px] font-black text-red-500 uppercase tracking-[0.2em] mb-0.5">⚠️ {activeRadarAlert.type.toUpperCase()} LIVE</p>
                <h3 className="text-sm font-bold text-white truncate uppercase tracking-tight">{activeRadarAlert.location || activeRadarAlert.city}</h3>
                <p className="text-[8px] font-bold text-white/40 uppercase tracking-widest mt-0.5">LARGËSIA: {Math.round(activeRadarAlert.currentDistance)}m</p>
              </div>
              <Radio className="w-5 h-5 text-red-500/30 animate-pulse absolute right-4" />
            </div>
          </div>
        )}

        {activeModule === 'drag' && !isDriving && (
          <div className="flex flex-col items-center gap-3 mb-6 apple-slide-up stagger-1 w-full px-2">
             <p className="text-[8px] font-bold text-white/30 uppercase tracking-[0.4em]">ZGJIDH MODIN OBLIGATIV</p>
             <div className="flex flex-wrap gap-1.5 bg-black/40 p-1.5 rounded-2xl border border-white/5 backdrop-blur-md w-full justify-center">
                {(['0-60', '0-100', '100-200', '1/4mile', 'ALL'] as RunMode[]).map((mode) => (
                  <button key={mode} onClick={() => setRunMode(mode)} className={cn("flex-1 min-w-[60px] py-2.5 rounded-xl font-bold text-[9px] uppercase tracking-widest transition-all", runMode === mode ? "bg-yellow-500 text-black shadow-lg" : "text-white/30 hover:text-white/60")}>{mode === '1/4mile' ? '1/4 MILE' : mode}</button>
                ))}
             </div>
          </div>
        )}

        {isDragModule && countdown > 0 && (
          <div className="flex gap-2.5 mb-8 apple-scale-in">
            {[1, 2, 3, 4, 5].map(i => (
              <div key={i} className={cn(
                "w-5 h-5 rounded-full border-2 border-white/5 transition-all duration-500",
                countdown >= i ? "bg-red-600 shadow-[0_0_15px_rgba(220,38,38,0.6)] border-red-500" : "bg-zinc-900"
              )} />
            ))}
            <div className={cn(
              "w-5 h-5 rounded-full border-2 border-white/5 transition-all duration-700",
              countdown === 6 ? "bg-green-500 shadow-[0_0_20px_rgba(34,197,94,0.8)] border-green-400" : "bg-zinc-900"
            )} />
          </div>
        )}

        <div className="relative w-full aspect-square flex items-center justify-center apple-scale-in stagger-2">
          <svg width="100%" height="100%" viewBox="0 0 340 340" className="max-w-full overflow-visible">
            <defs>
              <filter id="needleGlow" x="-50%" y="-50%" width="200%" height="200%"><feGaussianBlur stdDeviation="5" result="coloredBlur" /><feMerge><feMergeNode in="coloredBlur" /><feMergeNode in="SourceGraphic" /></feMerge></filter>
              <linearGradient id="arcGradient" x1="0%" y1="0%" x2="100%" y2="0%"><stop offset="0%" stopColor={themeColor} stopOpacity="0.1" /><stop offset="100%" stopColor={themeColor} stopOpacity="0.9" /></linearGradient>
            </defs>
            {Array.from({ length: 81 }).map((_, i) => {
              const val = i / 10;
              const angle = 135 + (val / 8) * (405 - 135);
              const isMajor = i % 10 === 0;
              const angleRad = (angle - 90) * Math.PI / 180;
              return (
                <g key={i}>
                  <line x1={170 + (140 - (isMajor ? 18 : 8)) * Math.cos(angleRad)} y1={170 + (140 - (isMajor ? 18 : 8)) * Math.sin(angleRad)} x2={170 + 140 * Math.cos(angleRad)} y2={170 + 140 * Math.sin(angleRad)} stroke={val >= 6.8 ? "#ef4444" : themeColor} strokeWidth={isMajor ? 3 : 1} opacity={isMajor ? 0.9 : 0.25} />
                  {isMajor && <text x={170 + 102 * Math.cos(angleRad)} y={170 + 102 * Math.sin(angleRad)} fill={val >= 6.8 ? "#ef4444" : themeColor} fontSize="13" fontWeight="700" textAnchor="middle" alignmentBaseline="middle" className="opacity-70 font-bold">{val}</text>}
                </g>
              );
            })}
            <path d={describeArc(170, 170, 136, 135, currentProgressAngle)} fill="none" stroke="url(#arcGradient)" strokeWidth="7" strokeLinecap="round" style={{ filter: 'url(#needleGlow)' }} />
            <line x1={170 + 50 * Math.cos((currentProgressAngle - 90) * Math.PI / 180)} y1={170 + 50 * Math.sin((currentProgressAngle - 90) * Math.PI / 180)} x2={170 + 136 * Math.cos((currentProgressAngle - 90) * Math.PI / 180)} y2={170 + 136 * Math.sin((currentProgressAngle - 90) * Math.PI / 180)} stroke={rpmValue > 6.8 ? "#ef4444" : "#ffffff"} strokeWidth="5" strokeLinecap="round" style={{ filter: 'url(#needleGlow)' }} />
          </svg>
          <div className="absolute inset-0 flex flex-col items-center justify-center overflow-hidden">
                <div className="text-center flex flex-col items-center">
                    <span className={cn("text-8xl font-bold tracking-tighter tabular-nums leading-none drop-shadow-[0_0_20px_rgba(255,255,255,0.1)]", isDragModule ? "text-yellow-500" : "text-white")}>{Math.round(displaySpeed)}</span>
                    <span className="text-sm font-light text-white/40 uppercase tracking-[0.5em] mt-3">km/h</span>
                    {isDragModule && dragTime !== null && dragTime > 0 && (
                      <div className="mt-4 animate-in fade-in slide-in-from-bottom-3 duration-500">
                        <p className="text-[10px] font-bold text-yellow-500/60 uppercase tracking-widest">KOHA {runMode}</p>
                        <p className="text-4xl font-bold text-yellow-500">{dragTime.toFixed(2)}s</p>
                      </div>
                    )}
                </div>
          </div>
        </div>

        <div className="w-full mt-8 space-y-5 apple-slide-up stagger-4 px-2 z-20">
           {isDragModule && speed > 1.5 && !isDriving && (
             <div className="bg-red-600/10 border border-red-600/20 p-4 rounded-2xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
               <AlertCircle className="w-5 h-5 text-red-500 shrink-0" />
               <p className="text-[9px] font-bold text-red-500 uppercase leading-relaxed tracking-wider">DUHET TË JESH 0 KM/H PËR TË FILLUAR RUN</p>
             </div>
           )}

           {isJumpStart && (
             <Badge className="w-full bg-red-600 text-white font-bold h-10 rounded-xl justify-center uppercase tracking-widest animate-pulse">🔥 JUMP START - ANULOHET</Badge>
           )}

           <Button
              onClick={() => {
                if (isDriving) { if (!isDragModule) stopTrip(); } 
                else if (isDragModule) { if (speed <= 1.5) startDragCountdown(); } 
                else { startTrip(); }
              }}
              disabled={isDragModule && speed > 1.5 && !isDriving}
              className={cn(
                "w-full h-20 rounded-[2.2rem] font-black text-base uppercase tracking-[0.25em] transition-all shadow-2xl border-b-4 active:scale-[0.97]",
                isDriving ? "bg-red-600 text-white hover:bg-red-700 border-red-800" : isDragModule ? "bg-yellow-500 text-black hover:bg-yellow-400 border-yellow-700 shadow-yellow-500/30" : "bg-accent text-background hover:bg-accent/90 border-accent/70 shadow-accent/30",
                isDragModule && speed > 1.5 && !isDriving && "opacity-40 grayscale grayscale pointer-events-none"
              )}
            >
              {isDriving ? (
                <div className="flex items-center gap-3 font-black">
                  {isDragModule ? <Loader2 className="w-5 h-5 animate-spin" /> : <Square className="w-5 h-5 fill-current" />} 
                  {isDragModule ? "RECORDING" : "NDALO UDHËTIMIN"}
                </div>
              ) : (
                <div className="flex items-center gap-3 font-black">
                  {isDragModule ? <Zap className="w-6 h-6 fill-current" /> : <Navigation className="w-6 h-6 fill-current" />}
                  {isDragModule ? "NIS GARËN" : "FILLO UDHËTIMIN"}
                </div>
              )}
            </Button>

           {isDriving && (
              <div className="grid grid-cols-3 gap-3 animate-in fade-in slide-in-from-bottom-4 duration-700">
                {isDragModule ? (
                  <>
                    <Card className="bg-yellow-500/5 border border-white/5 p-4 rounded-[1.8rem] flex flex-col items-center backdrop-blur-md">
                      <Timer className="w-4 h-4 text-yellow-500 mb-1.5" />
                      <span className="text-[14px] font-bold text-yellow-500">{(dragTime || 0).toFixed(2)}s</span>
                    </Card>
                    <Card className="bg-yellow-500/5 border border-white/5 p-4 rounded-[1.8rem] flex flex-col items-center backdrop-blur-md">
                      <MapPin className="w-4 h-4 text-yellow-500 mb-1.5" />
                      <span className="text-[14px] font-bold text-white">{Math.round(tripDistance)}m</span>
                    </Card>
                    <Card className="bg-yellow-500/5 border border-white/5 p-4 rounded-[1.8rem] flex flex-col items-center backdrop-blur-md">
                      <Gauge className="w-4 h-4 text-yellow-500 mb-1.5" />
                      <span className="text-[14px] font-bold text-white">{Math.round(peakSpeed)}</span>
                    </Card>
                  </>
                ) : (
                  <>
                    <Card className="bg-accent/5 border border-white/5 p-4 rounded-[1.8rem] flex flex-col items-center backdrop-blur-md">
                      <MapPin className="w-4 h-4 text-accent mb-1.5" /><span className="text-[14px] font-bold text-accent">{(tripDistance / 1000).toFixed(2)}</span>
                    </Card>
                    <Card className="bg-accent/5 border border-white/5 p-4 rounded-[1.8rem] flex flex-col items-center backdrop-blur-md">
                      <Gauge className="w-4 h-4 text-accent mb-1.5" /><span className="text-[14px] font-bold text-white">{Math.round((tripDistance / (tripTime || 1)) * 3.6)}</span>
                    </Card>
                    <Card className="bg-accent/5 border border-white/5 p-4 rounded-[1.8rem] flex flex-col items-center backdrop-blur-md">
                      <Clock className="w-4 h-4 text-accent mb-1.5" /><span className="text-[14px] font-bold text-white">{Math.floor(tripTime / 60)}:{(tripTime % 60).toFixed(0).padStart(2, '0')}</span>
                    </Card>
                  </>
                )}
              </div>
           )}
           
           {!isDriving && (peakSpeed > 0 || lastRunSummary) && (
             <Button variant="ghost" onClick={resetTrip} className="w-full h-12 rounded-2xl font-bold text-[10px] uppercase tracking-widest text-zinc-500 hover:text-white active:scale-95 transition-all"><RotateCcw className="w-3.5 mr-2" /> RESETO TELEMETRINË</Button>
           )}
        </div>
      </div>

      <Dialog modal={true} open={!!lastRunSummary} onOpenChange={(open) => !open && setLastRunSummary(null)}>
        <DialogContent className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-lg bg-transparent border-none shadow-none p-0 outline-none overflow-visible z-[1000]">
          <Carousel opts={{ align: "center", containScroll: false }} className="w-full">
            <CarouselContent className="ml-0">
              <CarouselItem className="pl-0 basis-[88%] flex justify-center">
                <div className="w-full max-w-[340px] bg-zinc-950 border border-white/10 rounded-[2.5rem] p-5 flex flex-col h-full max-h-[75dvh] overflow-y-auto no-scrollbar shadow-2xl mx-auto">
                  <div className="flex items-center justify-between mb-5 shrink-0">
                    <div>
                      <Badge className={cn("font-bold text-[8px] uppercase tracking-[0.2em] px-2 py-0.5 rounded-full mb-0.5", lastRunSummary?.runType === 'Top Speed' ? "bg-accent/10 text-accent" : "bg-yellow-500 text-black")}>STATISTIKAT</Badge>
                      <DialogTitle className="text-xl font-bold uppercase tracking-tighter text-white">{lastRunSummary?.runType}</DialogTitle>
                    </div>
                    <button onClick={() => setLastRunSummary(null)} className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center hover:bg-white/10 transition-colors active:scale-90"><X className="w-5 h-5 text-white/40" /></button>
                  </div>
                  
                  <div className="space-y-3 flex-1">
                    {lastRunSummary?.runType === 'ALL' && lastRunSummary.allStats ? (
                      <Card className="bg-white/5 border-white/5 p-4 rounded-[1.8rem] grid grid-cols-2 gap-3">
                        {Object.entries(lastRunSummary.allStats).map(([type, time]) => (
                          <div key={type} className="bg-white/5 p-3 rounded-xl border border-white/5 backdrop-blur-xl flex flex-col items-center">
                            <p className="text-[7px] font-light text-white/30 uppercase tracking-widest mb-1">{type}</p>
                            <p className="text-lg font-bold text-yellow-500">{time?.toFixed(2)}s</p>
                            <p className="text-[6px] font-bold text-white/20 mt-1 uppercase">Rank: #{getRank(type, time!, profile?.city)}</p>
                          </div>
                        ))}
                      </Card>
                    ) : (
                      <div className="space-y-3">
                        <Card className="bg-white/5 border-white/5 p-4 rounded-[1.8rem] space-y-4">
                          <div className="grid grid-cols-2 gap-3">
                            <div className="bg-white/5 p-4 rounded-xl border border-white/5 backdrop-blur-xl"><p className="text-[8px] font-light text-white/30 uppercase tracking-widest mb-1.5 text-center">ARRITJA</p><p className="text-xl font-bold text-accent text-center">{lastRunSummary?.time.toFixed(2)}s</p></div>
                            <div className="bg-white/5 p-4 rounded-xl border border-white/5 backdrop-blur-xl"><p className="text-[8px] font-light text-white/30 uppercase tracking-widest mb-1.5 text-center">MAX SPEED</p><p className="text-xl font-bold text-white text-center">{lastRunSummary?.peakSpeed} km/h</p></div>
                          </div>
                        </Card>

                        <div className="grid grid-cols-2 gap-2.5">
                           <Card className="bg-white/5 border-white/5 p-3 rounded-2xl flex items-center gap-3">
                              <div className="w-8 h-8 rounded-lg bg-red-500/10 flex items-center justify-center"><CircleSlash className="w-4 h-4 text-red-500" /></div>
                              <div className="text-left"><p className="text-[7px] font-bold text-white/30 uppercase tracking-widest">FRENA</p><p className="text-xs font-black text-white">{lastRunSummary?.brakes || 0}x</p></div>
                           </Card>
                           <Card className="bg-white/5 border-white/5 p-3 rounded-2xl flex items-center gap-3">
                              <div className="w-8 h-8 rounded-lg bg-blue-500/10 flex items-center justify-center"><RefreshCcw className="w-4 h-4 text-blue-500" /></div>
                              <div className="text-left"><p className="text-[7px] font-bold text-white/30 uppercase tracking-widest">KTHESA</p><p className="text-xs font-black text-white">{lastRunSummary?.turns || 0}x</p></div>
                           </Card>
                           <Card className="bg-white/5 border-white/5 p-3 rounded-2xl flex items-center gap-3">
                              <div className="w-8 h-8 rounded-lg bg-yellow-500/10 flex items-center justify-center"><ArrowDown className="w-4 h-4 text-yellow-500" /></div>
                              <div className="text-left"><p className="text-[7px] font-bold text-white/30 uppercase tracking-widest">NËN 10 KM/H</p><p className="text-xs font-black text-white">{lastRunSummary?.lowSpeedPasses || 0}x</p></div>
                           </Card>
                           <Card className="bg-white/5 border-white/5 p-3 rounded-2xl flex items-center gap-3">
                              <div className="w-8 h-8 rounded-lg bg-green-500/10 flex items-center justify-center"><TrendingUp className="w-4 h-4 text-green-500" /></div>
                              <div className="text-left"><p className="text-[7px] font-bold text-white/30 uppercase tracking-widest">ACCEL G</p><p className="text-xs font-black text-white">{lastRunSummary?.maxGForce || 0} G</p></div>
                           </Card>
                        </div>
                      </div>
                    )}
                    <p className="text-center text-[9px] font-bold text-white/20 uppercase tracking-[0.3em] mt-2">RRËSHQIT PËR RANKING <ChevronRight className="inline w-3 h-3" /></p>
                  </div>
                </div>
              </CarouselItem>
              <CarouselItem className="pl-4 basis-[88%] flex justify-center">
                <div className="w-full max-w-[340px] bg-zinc-950 border border-white/10 rounded-[2.5rem] p-5 flex flex-col h-full max-h-[75dvh] overflow-y-auto no-scrollbar shadow-2xl mx-auto">
                  <div className="flex items-center justify-between mb-5 shrink-0">
                    <div>
                      <Badge className="bg-accent/10 text-accent font-bold text-[8px] uppercase tracking-[0.2em] border-accent/20 px-2 py-0.5 rounded-full mb-0.5">POZICIONIMI</Badge>
                      <DialogTitle className="text-xl font-bold uppercase tracking-tighter text-white">DRIVERANK</DialogTitle>
                    </div>
                    <button onClick={() => setLastRunSummary(null)} className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center hover:bg-white/10 transition-colors active:scale-90"><X className="w-5 h-5 text-white/40" /></button>
                  </div>
                  <div className="space-y-3 flex-1">
                    <Card className="bg-accent/5 border-accent/20 p-4 rounded-[1.8rem] flex flex-col items-center justify-center text-center space-y-5">
                      <div className="w-full h-44 bg-accent/5 rounded-[2rem] flex items-center justify-center shadow-[0_0_25px_rgba(77,224,244,0.2)] border-2 border-accent/10 overflow-hidden shrink-0">
                        <RouteMap points={lastRunSummary?.points || []} />
                      </div>
                      <div className="space-y-2 w-full">
                         <div className="flex items-center gap-3 bg-white/5 px-4 py-3 rounded-xl border border-white/10 backdrop-blur-xl"><Star className="w-5 h-5 text-accent fill-accent" /><div className="text-left"><p className="text-[7px] font-light text-white/30 uppercase tracking-widest">{profile?.city?.toUpperCase() || "QYTETI"} RANK</p><p className="text-xs font-bold tracking-tight text-white">{currentRunRanks.city !== "--" ? `${currentRunRanks.city}st place on ${profile?.city}` : "MULTIPLE RANKS"}</p></div></div>
                         <div className="flex items-center gap-3 bg-white/5 px-4 py-3 rounded-xl border border-white/10 backdrop-blur-xl"><Activity className="w-5 h-5 text-white/40" /><div className="text-left"><p className="text-[7px] font-light text-white/30 uppercase tracking-widest">KOSOVA RANK</p><p className="text-xs font-bold uppercase tracking-tight text-white/60">{currentRunRanks.kosovo !== "--" ? `NR. ${currentRunRanks.kosovo} SOT` : "CALCULATING..."}</p></div></div>
                      </div>
                    </Card>
                  </div>
                  <Button onClick={handleSaveToLeaderboard} disabled={isSaving} className="w-full mt-4 h-14 bg-accent text-background font-bold uppercase text-xs tracking-[0.2em] rounded-xl shadow-xl active:scale-[0.98] transition-all border-b-4 border-accent/70 shrink-0">
                    {isSaving ? <Loader2 className="w-6 h-6 animate-spin" /> : <div className="flex items-center gap-2">PUBLIKO TANI <ChevronRight className="w-5 h-5" /></div>}
                  </Button>
                </div>
              </CarouselItem>
            </CarouselContent>
          </Carousel>
        </DialogContent>
      </Dialog>

      <BottomNav />
    </div>
  );
}
